"use client";

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { DrumRoll } from '@/components/ui/DrumRoll';
import { MatrixLayout } from '@/components/layout/MatrixLayout';
import { AxisItem, CellData } from '@/types/matrix';

// --- 初期データ ---
const INITIAL_TEMPLATES = {
  year: [
    { title: '決算報告書' },
    { title: '総勘定元帳' },
    { title: '法人税申告書' },
    { title: '消費税申告書' },
    { title: '勘定科目内訳書' },
  ],
  perm: [
    { title: '定款' },
    { title: '履歴事項全部証明書' },
    { title: '株主名簿' },
    { title: '設立届出書' },
  ]
};

const INITIAL_CLIENTS: AxisItem[] = [
  { id: 'c1', label: '株式会社 鈴木商店', subLabel: 'ID: 1001', clientDriveSetting: { isConnected: true, folderId: 'folder_abc' } },
  { id: 'c2', label: '合同会社 テック', subLabel: 'ID: 1002' },
  { id: 'c3', label: '佐藤 健太（個人）', subLabel: 'ID: 2005' },
  { id: 'c4', label: '山田不動産', subLabel: 'ID: 3040' },
  { id: 'c5', label: '東京コンサルティング', subLabel: 'ID: 5001' },
];

const INITIAL_PERIODS: AxisItem[] = [
  { id: 'perm', label: '永続', subLabel: 'PERMANENT', type: 'special' },
  { id: 'r6', label: 'R6', subLabel: '2024' },
  { id: 'r5', label: 'R5', subLabel: '2023' },
  { id: 'r4', label: 'R4', subLabel: '2022' },
];

const MOCK_DRIVE_STORAGE = [
  { key: 'c1-r5', title: '決算報告書', category: 'template', url: null },
  { key: 'c1-r5', title: '法人税申告書', category: 'template', url: null },
];

export default function DocuGridPage() {
  const [clients, setClients] = useState(INITIAL_CLIENTS);
  const [periods, setPeriods] = useState(INITIAL_PERIODS);
  
  const [clientId, setClientId] = useState(clients[0].id);
  const [periodId, setPeriodId] = useState(periods[1].id);
  
  // UI制御
  const [searchTerm, setSearchTerm] = useState('');
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [clientSort, setClientSort] = useState<'default' | 'name' | 'id'>('default');
  const [periodSort, setPeriodSort] = useState<'newest' | 'oldest'>('newest');

  const [isTemplateEditMode, setIsTemplateEditMode] = useState(false);
  const [templates, setTemplates] = useState(INITIAL_TEMPLATES);
  const [viewStateFiles, setViewStateFiles] = useState<any[]>([]);
  
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [uploadTarget, setUploadTarget] = useState<{ title: string, category: 'template' | 'custom' } | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [previewFile, setPreviewFile] = useState<{ url: string | null, title: string } | null>(null);

  useEffect(() => {
    setViewStateFiles([...MOCK_DRIVE_STORAGE]);
  }, []);

  // --- フィルタリング & ソート ---
  const filteredClients = useMemo(() => {
    let result = [...clients];
    if (searchTerm) {
      const lower = searchTerm.toLowerCase();
      result = result.filter(c => 
        c.label.toLowerCase().includes(lower) || 
        c.subLabel?.toLowerCase().includes(lower)
      );
    }
    if (clientSort === 'name') {
      result.sort((a, b) => a.label.localeCompare(b.label, 'ja'));
    } else if (clientSort === 'id') {
      result.sort((a, b) => (a.subLabel || '').localeCompare(b.subLabel || ''));
    }
    return result;
  }, [clients, searchTerm, clientSort]);

  const sortedPeriods = useMemo(() => {
    let result = [...periods];
    const perm = result.find(p => p.id === 'perm');
    const others = result.filter(p => p.id !== 'perm');
    if (periodSort !== 'newest') others.reverse();
    return perm ? [perm, ...others] : others;
  }, [periods, periodSort]);

  // --- ハンドラ ---
  const handleAddClient = () => {
    const name = prompt("新しい取引先名を入力してください");
    if (!name) return;
    const code = prompt("管理コードを入力してください", Math.floor(1000 + Math.random() * 9000).toString());
    const newClient: AxisItem = {
      id: `c_${Date.now()}`,
      label: name,
      subLabel: `ID: ${code || '0000'}`,
    };
    setClients(prev => [...prev, newClient]);
    setClientId(newClient.id);
  };

  const handleAddPeriod = () => {
    const label = prompt("新しい年度を入力してください（例：R7）");
    if (!label) return;
    const year = prompt("西暦を入力してください", new Date().getFullYear().toString());
    const newPeriod: AxisItem = {
      id: `p_${Date.now()}`,
      label: label,
      subLabel: year || '',
    };
    setPeriods(prev => {
      const [perm, ...rest] = prev;
      return [perm, newPeriod, ...rest];
    });
    setPeriodId(newPeriod.id);
  };

  // ファイル操作系
  const handleUploadClick = (title: string, category: 'template' | 'custom') => {
    if (isTemplateEditMode) return;
    setUploadTarget({ title, category });
    fileInputRef.current?.click();
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !uploadTarget) return;
    setIsUploading(true);
    const key = `${clientId}-${periodId}`;
    const formData = new FormData();
    formData.append('file', file);
    formData.append('folderName', `Client_${clientId}/${periodId}`);
    try {
      const res = await fetch('/api/upload', { method: 'POST', body: formData });
      if (!res.ok) throw new Error('Upload failed');
      const objectUrl = URL.createObjectURL(file);
      const newFile = {
        key: key,
        title: uploadTarget.category === 'template' ? uploadTarget.title : file.name,
        category: uploadTarget.category,
        url: objectUrl,
      };
      setViewStateFiles(prev => [...prev, newFile]);
      MOCK_DRIVE_STORAGE.push(newFile as any);
    } catch (error) {
      alert('アップロードに失敗しました');
    } finally {
      setIsUploading(false);
      setUploadTarget(null);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleCardClick = (item: CellData) => {
    if (isTemplateEditMode) return;
    if (item.isFilled) {
      const key = `${clientId}-${periodId}`;
      const targetFile = viewStateFiles.find(f => f.key === key && f.title === item.title);
      setPreviewFile({ title: item.title, url: targetFile?.url || null });
    } else {
      handleUploadClick(item.title, item.category);
    }
  };

  const handleUnlinkFile = (fileTitle: string) => {
    const key = `${clientId}-${periodId}`;
    if(!confirm(`「${fileTitle}」の連携を解除しますか？`)) return;
    setViewStateFiles(prev => prev.filter(f => !(f.key === key && f.title === fileTitle)));
  };

  const handleResync = () => {
    const key = `${clientId}-${periodId}`;
    const currentTitles = viewStateFiles.filter(f => f.key === key).map(f => f.title);
    const missingFiles = MOCK_DRIVE_STORAGE.filter(f => f.key === key && !currentTitles.includes(f.title));
    if (missingFiles.length > 0) {
      setViewStateFiles(prev => [...prev, ...missingFiles]);
      alert(`${missingFiles.length}件のファイルを復元しました。`);
    } else {
      alert("同期ズレはありません。");
    }
  };

  const handleAddTemplate = () => {
    const name = prompt("新しい必須書類の名称を入力してください");
    if (!name) return;
    const type = periodId === 'perm' ? 'perm' : 'year';
    setTemplates(prev => ({ ...prev, [type]: [...prev[type], { title: name }] }));
  };

  const handleDeleteTemplate = (titleToDelete: string) => {
    if (!confirm(`必須枠「${titleToDelete}」を削除しますか？`)) return;
    const type = periodId === 'perm' ? 'perm' : 'year';
    setTemplates(prev => ({ ...prev, [type]: prev[type].filter(t => t.title !== titleToDelete) }));
  };

  const currentData: CellData[] = useMemo(() => {
    const key = `${clientId}-${periodId}`;
    const uploads = viewStateFiles.filter(f => f.key === key);
    const templateType = periodId === 'perm' ? 'perm' : 'year';
    const requiredDocs: CellData[] = templates[templateType].map((tmpl, idx) => {
      const isUploaded = uploads.some(u => u.category === 'template' && u.title === tmpl.title);
      return { id: `req-${idx}`, title: tmpl.title, isFilled: isUploaded, category: 'template' };
    });
    const templateTitles = templates[templateType].map(t => t.title);
    const customDocs: CellData[] = uploads
      .filter(u => !templateTitles.includes(u.title))
      .map((u, idx) => ({ id: `custom-${idx}`, title: u.title, isFilled: true, category: 'custom' }));
    return [...requiredDocs, ...customDocs];
  }, [clientId, periodId, templates, viewStateFiles]);

  const progress = useMemo(() => {
    const requiredOnly = currentData.filter(d => d.category === 'template');
    if (!requiredOnly.length) return 0;
    const filled = requiredOnly.filter(d => d.isFilled).length;
    return Math.round((filled / requiredOnly.length) * 100);
  }, [currentData]);

  const selectedClient = clients.find(c => c.id === clientId);
  const selectedPeriod = periods.find(p => p.id === periodId);

  return (
    <MatrixLayout
      // ★上部ドラム：シンプルさを取り戻す！
      topDrum={
        <div className="relative w-full h-full flex items-center">
          {/* ドラムロール本体 (幅いっぱい) */}
          <div className="flex-1 h-full overflow-hidden">
             <DrumRoll items={filteredClients} direction="horizontal" selectedId={clientId} onSelect={setClientId} />
          </div>

          {/* 右端のグラデーションマスク (UIの裏側を通す) */}
          <div className="absolute right-0 top-0 w-24 h-full bg-gradient-to-l from-[#0f172a] to-transparent pointer-events-none z-10"></div>

          {/* ★ツールボタン群 (右上にフロートさせる) */}
          <div className="absolute right-4 top-1/2 -translate-y-1/2 flex items-center gap-2 z-50">
            
            {/* 検索・ソートトグル */}
            <button 
              onClick={() => setIsSearchOpen(!isSearchOpen)}
              className={`w-8 h-8 rounded-full flex items-center justify-center transition-all shadow-lg border border-white/10 ${isSearchOpen ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700 hover:text-white'}`}
              title="検索・並び替え"
            >
              🔍
            </button>

            {/* 追加ボタン */}
            <button 
              onClick={handleAddClient}
              className="w-8 h-8 rounded-full bg-slate-800 text-slate-400 hover:bg-blue-600 hover:text-white flex items-center justify-center transition-all shadow-lg border border-white/10"
              title="取引先を追加"
            >
              <span className="text-lg font-bold pb-1">+</span>
            </button>
          </div>

          {/* ★検索メニュー (開いたときだけポップオーバー表示) */}
          {isSearchOpen && (
             <div className="absolute top-full right-4 mt-2 w-64 bg-slate-800 p-4 rounded-xl shadow-2xl border border-slate-700 z-[100] animate-[fadeInDown_0.2s_ease-out]">
                <input 
                  type="text"
                  autoFocus
                  placeholder="取引先を検索..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full bg-slate-900 text-white text-sm px-3 py-2 rounded-lg border border-slate-600 focus:border-blue-500 focus:outline-none mb-3"
                />
                
                <div className="text-[10px] text-slate-400 font-bold mb-1 uppercase">並び替え</div>
                <div className="flex gap-2">
                  <button onClick={() => setClientSort('default')} className={`flex-1 py-1 text-xs rounded border ${clientSort === 'default' ? 'bg-blue-600 border-blue-600 text-white' : 'border-slate-600 text-slate-400 hover:border-slate-400'}`}>登録順</button>
                  <button onClick={() => setClientSort('name')} className={`flex-1 py-1 text-xs rounded border ${clientSort === 'name' ? 'bg-blue-600 border-blue-600 text-white' : 'border-slate-600 text-slate-400 hover:border-slate-400'}`}>名前順</button>
                </div>
             </div>
          )}
        </div>
      }
      
      // ★左側ドラム：ズレを直し、余計な文字を削除
      leftDrum={
        <div className="relative h-full w-full flex flex-col items-center">
          {/* ドラムロール本体 (縦中央揃え) */}
          <div className="flex-1 w-full overflow-hidden flex justify-center">
            <DrumRoll items={sortedPeriods} direction="vertical" selectedId={periodId} onSelect={setPeriodId} />
          </div>

          {/* 下端のグラデーションマスク */}
          <div className="absolute bottom-0 left-0 h-24 w-full bg-gradient-to-t from-[#0f172a] to-transparent pointer-events-none z-10"></div>
          
          {/* ★年度追加ボタン (一番下にフロート) */}
          <button 
            onClick={handleAddPeriod}
            className="absolute bottom-4 left-1/2 -translate-x-1/2 w-8 h-8 rounded-full bg-slate-800 text-slate-400 hover:bg-blue-600 hover:text-white flex items-center justify-center transition-all shadow-lg border border-white/10 z-50"
            title="年度を追加"
          >
            <span className="text-lg font-bold pb-1">+</span>
          </button>
        </div>
      }
      headerTitle={
        <div>
          <div className="flex items-center justify-between mb-1">
            <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
              {selectedClient?.label}
              {selectedClient?.clientDriveSetting?.isConnected && (
                <span className="flex items-center gap-1 bg-green-50 text-green-600 px-1.5 py-0.5 rounded text-[9px] border border-green-100 animate-pulse">
                  <span className="w-1.5 h-1.5 rounded-full bg-green-500"></span>
                  Sync ON
                </span>
              )}
            </div>
          </div>
          <div className="text-xl font-bold text-slate-800 leading-tight flex items-center gap-2">
            <span className={periodId === 'perm' ? 'text-yellow-500' : 'text-blue-600'}>{selectedPeriod?.label}</span>
            <span>{periodId === 'perm' ? '永久保存ドキュメント' : '確定申告・決算資料'}</span>
            <button 
              onClick={() => setIsTemplateEditMode(!isTemplateEditMode)}
              className={`ml-4 text-xs px-3 py-1 rounded-full border transition-all ${isTemplateEditMode ? 'bg-yellow-500 text-white border-yellow-500 shadow-md' : 'bg-white text-slate-400 border-slate-200 hover:border-blue-400 hover:text-blue-500'}`}
            >
              {isTemplateEditMode ? '完了' : '枠の設定'}
            </button>
            <button onClick={handleResync} className="ml-2 text-xs px-3 py-1 rounded-full bg-slate-100 text-slate-500 hover:bg-slate-200 hover:text-slate-700 transition-colors flex items-center gap-1">
              <span>🔄</span>
            </button>
          </div>
        </div>
      }
      progress={progress}
      progressColor={periodId === 'perm' ? 'text-yellow-500' : 'text-blue-600'}
    >
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6 pb-20">
        <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileChange} accept=".pdf,.png,.jpg,.jpeg,.xlsx,.docx" />

        {currentData.map((item) => (
          <div 
            key={item.id}
            onClick={() => handleCardClick(item)}
            className={`
              relative h-40 rounded-2xl p-5 flex flex-col justify-between transition-all cursor-pointer group
              ${isTemplateEditMode ? 'border-2 border-yellow-400 bg-yellow-50/20' : ''}
              ${!isTemplateEditMode && item.isFilled 
                ? 'bg-white shadow-sm border-l-4 hover:shadow-lg hover:scale-105' 
                : !isTemplateEditMode ? 'bg-slate-50 border-2 border-dashed border-slate-300 hover:bg-white hover:border-blue-400' : ''
              }
              ${!isTemplateEditMode && item.isFilled && item.category === 'template' ? 'border-indigo-500' : ''}
              ${!isTemplateEditMode && item.isFilled && item.category === 'custom' ? 'border-orange-400' : ''} 
            `}
          >
            {isTemplateEditMode && item.category === 'template' && (
              <button onClick={(e) => { e.stopPropagation(); handleDeleteTemplate(item.title); }} className="absolute -top-2 -right-2 w-6 h-6 bg-red-500 text-white rounded-full flex items-center justify-center shadow-lg hover:scale-110 z-50 font-bold">×</button>
            )}
            {!isTemplateEditMode && item.isFilled && (
              <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity z-40">
                 <button onClick={(e) => { e.stopPropagation(); handleUnlinkFile(item.title); }} className="bg-slate-100/80 hover:bg-red-50 text-slate-400 hover:text-red-500 p-1.5 rounded-lg backdrop-blur-sm border border-slate-200 transition-colors"><span className="text-sm">🔗×</span></button>
              </div>
            )}
            <div className="absolute -top-3 left-4 z-30">
              {item.category === 'template' ? (
                <span className="bg-slate-200 text-slate-600 text-[10px] font-bold px-2 py-1 rounded-full border border-white shadow-sm">必須</span>
              ) : (
                <span className="bg-orange-100 text-orange-600 text-[10px] font-bold px-2 py-1 rounded-full border border-white shadow-sm">追加</span>
              )}
            </div>
            {item.isFilled ? (
              <>
                <div className="flex justify-between items-start pt-2">
                  <span className="text-[10px] font-bold bg-slate-100 text-slate-500 px-2 py-1 rounded uppercase tracking-wider">PDF</span>
                  <div className={`w-5 h-5 rounded-full flex items-center justify-center text-white text-xs ${item.category === 'custom' ? 'bg-orange-400' : 'bg-green-500'}`}>✓</div>
                </div>
                <div>
                  <h3 className="font-bold text-slate-700 text-sm leading-tight line-clamp-2">{item.title}</h3>
                  <p className="text-[10px] text-slate-400 mt-1 font-mono truncate">Submitted.pdf</p>
                </div>
              </>
            ) : (
              <div className="flex flex-col items-center justify-center h-full text-center pt-2">
                <div className="w-10 h-10 rounded-full bg-slate-200 text-slate-400 group-hover:bg-blue-100 group-hover:text-blue-500 flex items-center justify-center mb-2 transition-colors">
                  <span className="text-xl font-bold">+</span>
                </div>
                <h3 className="font-bold text-slate-400 text-sm group-hover:text-blue-600 transition-colors">
                  {isUploading && uploadTarget?.title === item.title ? '送信中...' : item.title}
                </h3>
              </div>
            )}
          </div>
        ))}

        {isTemplateEditMode && (
          <div onClick={handleAddTemplate} className="h-40 rounded-2xl border-4 border-dashed border-yellow-300 flex flex-col items-center justify-center text-yellow-500 bg-yellow-50 hover:bg-yellow-100 cursor-pointer transition-all gap-2 animate-[wiggle_0.4s_ease-in-out_infinite_reverse]">
             <span className="text-4xl font-black">+</span>
             <span className="text-sm font-bold">枠を追加</span>
          </div>
        )}

        {!isTemplateEditMode && (
          <div onClick={() => handleUploadClick('新規ファイル', 'custom')} className="h-40 rounded-2xl border-2 border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-300 hover:border-orange-300 hover:text-orange-400 hover:bg-orange-50/10 cursor-pointer transition-all gap-2 group">
             <div className="w-10 h-10 rounded-full bg-slate-100 group-hover:bg-orange-100 flex items-center justify-center transition-colors">
                <span className="text-xl font-light">+</span>
             </div>
             <span className="text-xs font-bold">ファイルを追加</span>
          </div>
        )}
      </div>
      
      {isUploading && (
        <div className="fixed inset-0 bg-black/20 z-[100] flex items-center justify-center cursor-wait">
          <div className="bg-white px-6 py-4 rounded-xl shadow-2xl flex items-center gap-3 animate-bounce">
            <div className="w-4 h-4 border-2 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
            <span className="font-bold text-slate-700">Driveへ保存中...</span>
          </div>
        </div>
      )}

      {previewFile && (
        <div className="fixed inset-0 bg-black/80 z-[200] flex items-center justify-center p-4 md:p-10 animate-[fadeIn_0.2s_ease-out]" onClick={() => setPreviewFile(null)}>
          <div className="bg-slate-900 w-full h-full max-w-6xl rounded-2xl overflow-hidden flex flex-col relative shadow-2xl" onClick={(e) => e.stopPropagation()}>
            <div className="h-14 bg-slate-800 flex items-center justify-between px-6 border-b border-slate-700">
              <h2 className="text-white font-bold truncate">{previewFile.title}</h2>
              <button onClick={() => setPreviewFile(null)} className="text-slate-400 hover:text-white text-2xl font-bold leading-none">×</button>
            </div>
            <div className="flex-1 bg-slate-100 relative">
              {previewFile.url ? (
                <iframe src={previewFile.url} className="w-full h-full" title="PDF Preview" />
              ) : (
                <div className="flex flex-col items-center justify-center h-full text-slate-400 gap-4">
                  <div className="text-6xl">🔒</div>
                  <p>プレビューできません</p>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </MatrixLayout>
  );
}